INSERT INTO `question_answers` (`id`, `interview_id`, `question`, `answer`, `category`, `score`, `strengths`, `improvements`, `suggestions`) VALUES
(180, 19, 'How do you determine which design pattern to use in a given situation, and what are some common anti-patterns to avoid?', 'then', 'Primary role skills', 0, '[\"Good effort.\"]', '[\"Lack of understanding of design patterns\", \"Inability to identify anti-patterns\", \"Failure to provide relevant examples\"]', '[\"Study and review common iOS design patterns such as MVC, MVVM, and VIPER\", \"Research and understand anti-patterns in iOS development\", \"Practice explaining design pattern choices and trade-offs in a clear and concise manner\"]'),
(181, 19, 'Can you describe your experience with REST API design and implementation, and what considerations do you take into account when designing API endpoints?', 'ok', 'Secondary skills', 0, '[\"Good effort.\"]', '[\"Lack of relevant experience description\", \"No mention of API design considerations\", \"Insufficient technical details\"]', '[\"Study and review REST API design principles and best practices\", \"Prepare examples of API endpoint design and implementation from personal projects or previous experience\", \"Familiarize yourself with iOS-specific API integration frameworks and libraries, such as Alamofire or URLSession\"]'),
(182, 19, 'How do you handle errors and exceptions in a REST API, and what strategies do you use for API security and authentication?', 'then', 'Secondary skills', 0, '[\"Good effort.\"]', '[\"Lack of understanding of error handling and exception mechanisms in REST APIs\", \"No knowledge of API security and authentication strategies\", \"Inability to articulate relevant technical concepts\"]', '[\"Study and review error handling mechanisms in REST APIs, such as try-catch blocks and error response codes\", \"Research and implement API security strategies, including encryption, secure authentication protocols, and access control\", \"Familiarize yourself with iOS-specific security and authentication frameworks, such as Keychain and biometric authentication\"]'),
(183, 19, 'How do you use SwiftUI to create responsive and adaptive user interfaces, and what are some best practices for working with Auto Layout and Core Data?', 'then', 'Secondary skills', 0, '[\"Good effort.\"]', '[\"Lack of understanding of SwiftUI and its application in creating responsive user interfaces\", \"Inability to explain best practices for working with Auto Layout and Core Data\"]', '[\"Study and review Apple\'s official documentation on SwiftUI to understand its capabilities and best practices\", \"Practice building responsive and adaptive user interfaces using SwiftUI\", \"Review and implement Auto Layout and Core Data best practices in a personal project or contribution to an open-source project\", \"Prepare to provide specific examples and explanations of how to use these technologies in a technical interview setting\"]'),
(184, 19, 'Can you walk me through your process for debugging a complex layout issue in SwiftUI, and what tools do you use for performance optimization?', 'then', 'Secondary skills', 0, '[\"Good effort.\"]', '[\"Lack of understanding of the question\", \"Failure to provide a clear debugging process\", \"No mention of tools for performance optimization\"]', '[\"Review SwiftUI documentation and debugging techniques\", \"Familiarize yourself with Xcode\'s built-in debugging tools, such as the View Debugger and Instruments\", \"Practice explaining technical processes and tools used in iOS development, such as SwiftUI and Xcode\"]'),
(185, 20, 'How do you optimize the performance of a Java application that uses Oracle database, considering the SQL queries are complex and involve multiple joins?', 'I would optimise the performance of SQL by using indexes to make searching faster', 'Primary role skills', 40, '[\"Recognizes the importance of indexes for query performance\"]', '[\"Lack of understanding of Java application optimization\", \"Insufficient consideration of Oracle database specifics\", \"No mention of other optimization techniques such as caching, connection pooling, or query rewriting\"]', '[\"Study Java performance optimization techniques such as profiling and caching\", \"Investigate Oracle database optimization methods including partitioning and materialized views\", \"Research query optimization strategies like rewriting complex queries and avoiding correlated subqueries\", \"Consider the impact of indexing on insert, update, and delete operations\", \"Learn about connection pooling and its benefits for improving database performance in Java applications\"]'),
(186, 20, 'Can you provide an example of how you would rewrite a poorly performing SQL query to improve its efficiency?', 'I could improve the performance of SQL by reducing the number of lines in the code and using the code which is required to solve the problem', 'Primary role skills', 20, '[\"attempted to address performance improvement\"]', '[\"lacked specific examples\", \"did not provide technical details\", \"did not mention indexing, caching, or query optimization techniques\"]', '[\"study and practice rewriting SQL queries using techniques such as indexing, caching, and limiting result sets\", \"learn to explain technical concepts in a clear and concise manner\", \"review examples of poorly performing SQL queries and practice optimizing them for improved efficiency\"]'),
(187, 20, 'Explain the concept of encapsulation in C++ and how it helps in data hiding. Provide a simple example to illustrate this.', 'encapsulation in C++ is basically hiding the necessary information required without getting with ropt by the robbers 8 basically at the data', 'Primary role skills', 10, '[\"Good effort.\"]', '[\"Lack of understanding of encapsulation concept\", \"Inability to provide a clear and concise definition\", \"Failure to provide a relevant example\"]', '[\"Study the fundamentals of object-oriented programming in C++\", \"Review the concept of encapsulation and its importance in data hiding\", \"Practice providing simple examples to illustrate complex concepts, such as using a class with private members to demonstrate encapsulation\"]'),
(188, 20, 'How would you handle a situation where you need to access a private member variable of a class from another class?', 'I would use spring boot to access the private member variable of a class from one another class basically using auto wired', 'Primary role skills', 20, '[\"mentioned a framework (Spring Boot)\"]', '[\"lack of understanding of object-oriented programming principles\", \"inability to provide a clear and concise answer\", \"over-reliance on a framework without understanding the underlying concepts\"]', '[\"study object-oriented programming principles, specifically encapsulation and access modifiers\", \"learn about reflection and other ways to access private members in Java\", \"practice explaining technical concepts in a clear and concise manner\", \"review the basics of Spring Boot and its features, such as autowiring, to understand how to use them effectively\"]'),
(189, 20, 'Describe a scenario where you had to write a complex SQL query to retrieve data from multiple tables in an Oracle database. How did you approach this task?', 'I would name the all the tables with same name so the retrieval will be easier', 'Primary role skills', 0, '[\"Good effort.\"]', '[\"Lack of understanding of SQL query fundamentals\", \"Inability to approach complex data retrieval tasks\", \"Insufficient knowledge of database design principles\"]', '[\"Review the basics of SQL querying, including JOINs and subqueries\", \"Practice writing complex SQL queries to retrieve data from multiple tables\", \"Study database design principles to understand the importance of unique and descriptive table names\"]'),
(190, 20, 'How did you handle any errors or inconsistencies in the data that you encountered during the query execution?', 'a handle errors by using the basic principles which were learnt during classes basically following up the foundations of the subject', 'Primary role skills', 20, '[\"Mentioned following basic principles\"]', '[\"Lack of specificity\", \"No technical details provided\", \"No clear understanding of error handling\"]', '[\"Study error handling mechanisms in programming languages\", \"Review database query error handling techniques\", \"Practice implementing try-except blocks or error handling functions in code\"]'),
(191, 20, 'How do you approach data analysis when working with a large dataset, and what tools or techniques do you use to visualize the data?', 'basically I would use ibmsps 2026 to visualise the last data sets and I would clean the data using normalisation techniques', 'Secondary skills', 40, '[\"mentions data visualization\", \"awareness of data cleaning\"]', '[\"lack of clarity in explanation\", \"limited tools and techniques mentioned\", \"inaccurate tool name\"]', '[\"research industry-standard data analysis tools like Pandas, NumPy, and Matplotlib\", \"learn data visualization best practices using libraries like Seaborn and Plotly\", \"practice explaining technical concepts in a clear and concise manner\", \"familiarize yourself with data preprocessing techniques beyond normalization\", \"explore IBM data analysis tools, but ensure accuracy in naming and understanding their applications\"]'),
(192, 20, 'Can you walk me through a time when you had to communicate complex data insights to a non-technical stakeholder, and how you used data visualization to facilitate this?', 'recently I have clear day data set during my project I basically normalise the data  and filled empty data with the mock up data', 'Secondary skills', 20, '[\"attempted to provide a relevant example from their experience\"]', '[\"lacked clarity and specificity in their example\", \"did not demonstrate understanding of data visualization concepts\", \"failed to explain how they communicated insights to a non-technical stakeholder\"]', '[\"practice explaining technical concepts in simple terms\", \"study data visualization best practices and tools\", \"prepare examples that demonstrate ability to communicate complex data insights to non-technical stakeholders\", \"review the importance of data quality and handling missing data in a real-world scenario\"]'),
(193, 20, 'Explain the concept of Core Data and how it is used in applications that require complex data management. Provide an example of a project where you used Core Data to manage data.', 'core data is used to manager application whenever it is required basically all the backend and front end will be present at the core data', 'Secondary skills', 20, '[\"attempted to define Core Data\"]', '[\"lacking clarity and specificity\", \"failed to provide a relevant project example\", \"did not explain the concept of Core Data accurately\"]', '[\"study the official Apple documentation on Core Data to understand its purpose and functionality\", \"practice explaining technical concepts in a clear and concise manner\", \"prepare examples of personal projects that demonstrate data management skills, even if not directly related to Core Data\"]'),
(194, 20, 'How do you handle data migration and schema changes when using Core Data, and what strategies do you use to minimize downtime and data loss?', 'No answer provided.', 'Secondary skills', 0, '[\"Good effort.\"]', '[\"Provide a clear understanding of data migration and schema changes in Core Data\", \"Explain strategies for minimizing downtime and data loss\", \"Demonstrate knowledge of Core Data best practices\"]', '[\"Research and review Core Data documentation and tutorials\", \"Practice implementing data migration and schema changes in a sample project\", \"Review industry blogs and articles on minimizing downtime and data loss in Core Data migrations\"]'),
(195, 21, 'How would you design a scalable RESTful API using Spring Boot to handle high traffic and large data volumes?', '@RestController\n@RequestMapping(\"/api/v1/users\")\npublic class UserController {\n\n    private final UserService userService;\n\n    public UserController(UserService userService) {\n        this.userService = userService;\n    }\n\n    // Paginated GET endpoint\n    @GetMapping\n    public ResponseEntity<Page<UserDTO>> getUsers(Pageable pageable) {\n        return ResponseEntity.ok(userService.getAllUsers(pageable));\n    }\n\n    // Async POST endpoint\n    @PostMapping\n    public CompletableFuture<ResponseEntity<UserDTO>> createUser(@Valid @RequestBody UserDTO userDTO) {\n        return userService.createUser(userDTO)\n                          .thenApply(ResponseEntity::ok);\n    }\n}', 'Primary role skills', 80, '[\"Usage of Spring Boot annotations for RESTful API design\", \"Implementation of pagination for handling large data volumes\", \"Utilization of asynchronous programming for improving performance\"]', '[\"Lack of error handling and exception management\", \"Insufficient security measures for protecting sensitive data\", \"No clear indication of database connection pooling or transaction management\"]', '[\"Implement robust error handling using try-catch blocks and custom exception classes\", \"Integrate security frameworks like Spring Security for authentication and authorization\", \"Configure database connection pooling using libraries like HikariCP and implement transaction management using Spring Transactional annotations\"]'),
(196, 21, 'Can you explain how you would implement caching and load balancing to further improve performance?', 'To implement caching and load balancing for improved performance, consider the following strategies:\nLoad Balancing: Distribute incoming network traffic across multiple servers to ensure high availability and reliability. Use algorithms like Round Robin, Weighted Round Robin, or Least Connections to optimize traffic distribution based on server load and performance metrics. \n2\nCaching Strategies:\nBrowser Caching: Store static resources like images and CSS locally on the user\'s browser for faster access. \n1\nServer-Side Caching: Use tools like Redis or Memcached to cache frequently accessed data, reducing the need for repeated database queries. \n1\nContent Delivery Networks (CDNs): Distribute cached content geographically closer to users to reduce latency. \n1\nMulti-Layer Caching: Combine browser, CDN, and application cache layers to enhance performance and reduce server load. \n1\nCache Eviction Policies: Implement policies like Least Recently Used (LRU) or Time-To-Live (TTL) to manage cache freshness and ensure that outdated data is removed. \n2\n\nBy strategically combining these techniques, you can create a robust architecture that enhances performance and reliability in your applicatio', 'Primary role skills', 90, '[\"clearly explained load balancing algorithms\", \"identified multiple caching strategies\", \"mentioned cache eviction policies\"]', '[\"lacked specific examples or use cases\", \"did not discuss potential challenges or trade-offs\", \"could have provided more details on implementation\"]', '[\"provide concrete examples of load balancing and caching in a real-world application\", \"discuss potential pitfalls or limitations of caching and load balancing\", \"elaborate on how to implement and configure caching tools like Redis or Memcached\"]'),
